            [RegAttribute(Description = "0X30000 | (0X018 << 2),0x30060")]
            VersionInfo_DesignerWord2      = 0X30000 | (0X018 << 2),

            /// <summary>
            /// PRO_VERSION_DESIGNER_WORD3[read]
            /// abs-addr:0X30064; 版本信息，编译时间,,,,,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:pro_version_designer_word3
            /// bit-width:16 ;  64bits_info
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X019 << 2),0x30064")]
            VersionInfo_DesignerWord3      = 0X30000 | (0X019 << 2),

            /// <summary>
            /// PRO_VERSION_VERSION_WORD0[read]
            /// abs-addr:0X30068; 版本信息，版本号,,,,,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:pro_version_version_word0
            /// bit-width:16 ;  low_16bits_of_32bits
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X01A << 2),0x30068")]
            VersionInfo_VersionWord0       = 0X30000 | (0X01A << 2),

            /// <summary>
            /// PRO_VERSION_VERSION_WORD1[read]
            /// abs-addr:0X3006C; 16位数据，由此寄存器写入，再由此寄存器读出，两者数据一致，表明上电OK。,,,,,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:pro_version_version_word1
            /// bit-width:16 ;  high_16bits_of_32bits
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X01B << 2),0x3006C")]
            VersionInfo_VersionWord1       = 0X30000 | (0X01B << 2),
            #endregion VersionInfo

            #region====================VersionInfo1=[共4个寄存器]=============================

            /// <summary>
            /// REG_PRO_VERSION_COMMENT_WORD14[read]
            /// abs-addr:0X30028; 版本信息，备注,,,,,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:reg_pro_version_comment_word14
            /// bit-width:16 ;  256bits_info
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X00A << 2),0x30028")]
            VersionInfo1_CommentWord14     = 0X30000 | (0X00A << 2),

            /// <summary>
            /// REG_PRO_VERSION_COMMENT_WORD15[read]
            /// abs-addr:0X3002C; 版本信息，备注,,,,,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:reg_pro_version_comment_word15
            /// bit-width:16 ;  256bits_info
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X00B << 2),0x3002C")]
            VersionInfo1_CommentWord15     = 0X30000 | (0X00B << 2),

            /// <summary>
            /// REG_PRO_VERSION_TIME_WORD0[read]
            /// abs-addr:0X30050; 版本信息，编译时间,,,,,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:reg_pro_version_time_word0
            /// bit-width:16 ;  low_16bits_of_32bits
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X014 << 2),0x30050")]
            VersionInfo1_CompileTimeWord0  = 0X30000 | (0X014 << 2),

            /// <summary>
            /// REG_PRO_VERSION_TIME_WORD1[read]
            /// abs-addr:0X30054; 版本信息，版本号,,,,,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:reg_pro_version_time_word1
            /// bit-width:16 ;  high_16bits_of_32bits
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X015 << 2),0x30054")]
            VersionInfo1_CompileTimeWord1  = 0X30000 | (0X015 << 2),
            #endregion VersionInfo1

            #region====================dbi=[共3个寄存器]======================================

            /// <summary>
            /// DBI_FREQUENCY_INDEX[read]
            /// abs-addr:0X30190; none
            /// reg_hw_name:dbi_frequency_index
            /// bit-width:10 ;  指示最高幅度对应的频率值，[6]代表有效使能位
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X064 << 2),0x30190")]
            dbi_dbi_frequency_index        = 0X30000 | (0X064 << 2),

            /// <summary>
            /// DBI_MAX_AMPLITUDE_L16[read]
            /// abs-addr:0X30194; none
            /// reg_hw_name:dbi_max_amplitude_l16
            /// bit-width:16 ;  dbi频率计测量幅度值低16位
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X065 << 2),0x30194")]
            dbi_dbi_max_amplitude_l16      = 0X30000 | (0X065 << 2),

            /// <summary>
            /// DBI_MAX_AMPLITUDE_H8[read]
            /// abs-addr:0X30198; none
            /// reg_hw_name:dbi_max_amplitude_h8
            /// bit-width:8 ;  dbi频率计测量幅度值高8位
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X066 << 2),0x30198")]
            dbi_dbi_max_amplitude_h8       = 0X30000 | (0X066 << 2),
            #endregion dbi

            #region====================ext_10m=[共1个寄存器]==================================

            /// <summary>
            /// STATUS_OF_CLOCK[read]
            /// abs-addr:0X300C8; 是,,,,,,,,,,,,,,,,,,,
            /// reg_hw_name:status_of_clock
            /// bit-width:16 ;  [0]:外部10m锁定状态 1锁定，0未锁定
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X032 << 2),0x300C8")]
            ext_10m_status_of_clock        = 0X30000 | (0X032 << 2),
            #endregion ext_10m

            #region====================reverse=[共3个寄存器]==================================

            /// <summary>
            /// PRO_REVERSE_RD_REG_0[read]
            /// abs-addr:0X300A8; none
            /// reg_hw_name:pro_reverse_rd_reg_0
            /// bit-width:16 ;  处理板备用读寄存器
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X02A << 2),0x300A8")]
            reverse_pro_reverse_rd_reg_0   = 0X30000 | (0X02A << 2),

            /// <summary>
            /// PRO_REVERSE_RD_REG_1[read]
            /// abs-addr:0X300AC; none
            /// reg_hw_name:pro_reverse_rd_reg_1
            /// bit-width:16 ;  处理板备用读寄存器
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X02B << 2),0x300AC")]
            reverse_pro_reverse_rd_reg_1   = 0X30000 | (0X02B << 2),

            /// <summary>
            /// PRO_REVERSE_RD_REG_2[read]
            /// abs-addr:0X300B0; none
            /// reg_hw_name:pro_reverse_rd_reg_2
            /// bit-width:16 ;  处理板备用读寄存器
            /// </summary>
            [RegAttribute(Description = "0X30000 | (0X02C << 2),0x300B0")]
            reverse_pro_reverse_rd_reg_2   = 0X30000 | (0X02C << 2),
            #endregion reverse
        }
    }
}

